static unsigned char char_to_tile(char c) {
    uint8_t index;
    uint8_t row;
    uint8_t col;
    uint8_t tile_index;

    if (c >= 32 && c <= 126) {
        index = c - 32;     // ASCII 32 开始
        row = index >> 4;   // 每行 16 个字符
        col = index & 0x0F;

        // png2asset 实际 tile 顺序：两行一组，按列交错
        tile_index = ((row >> 1) * 32) + (col << 1) + (row & 1);

        return font_TILE_START + tile_index;
    }

    return font_TILE_START; // 空格
}

void draw_text(uint8_t x, uint8_t y, const char *text) {
    unsigned char tile;
    while (*text) {
        tile = char_to_tile(*text++);
        set_bkg_tiles(x++, y, 1, 1, &tile);
    }
}

void draw_uint16(uint8_t x, uint8_t y, uint16_t value, uint8_t width) {
    char buf[6];
    uint8_t i;
    if (width > 5) width = 5;
    for (i = 0; i < 5; i++) {
        buf[4 - i] = '0' + (value % 10);
        value /= 10;
    }
    buf[5] = '\0';
    draw_text(x, y, &buf[5 - width]);
}

void draw_uint8(uint8_t x, uint8_t y, uint8_t value, uint8_t width) {
    char buf[4];
    uint8_t i;

    if (width > 3) width = 3;

    for (i = 0; i < 3; i++) {
        buf[2 - i] = '0' + (value % 10);
        value /= 10;
    }

    buf[3] = '\0';

    draw_text(x, y, &buf[3 - width]);
}

void draw_uint32(uint8_t x, uint8_t y, uint32_t value, uint8_t width) {
    char buf[11];
    int8_t i;
    uint32_t max_value = 1;

    if (width > 10) width = 10;

    for (i = 0; i < width; i++) {
        max_value *= 10;
    }

    if (value >= max_value) {
        value = max_value - 1;
    }

    for (i = 9; i >= 0; i--) {
        buf[i] = (char)('0' + (value % 10u));
        value /= 10u;
    }

    buf[10] = '\0';
    draw_text(x, y, &buf[10 - width]);
}